+                int py = y >> 16;
+                px %= image_width;
+                py %= image_height;
+                if(px < 0) px += image_width;
+                if(py < 0) py += image_height;
+                int y_offset = py * scanline_offset;
+
+                assert(px >= 0 && px < image_width);
+                assert(py >= 0 && py < image_height);
