+    TArea   area;
+    int     cover;
+    int     invalid;
+
+    PCell   cells;
+    PVG_FT_PtrDist     max_cells;
+    PVG_FT_PtrDist     num_cells;
+
+    TPos    x,  y;
+
+    PVG_FT_Outline  outline;
