+  void
+  PVG_FT_Raster_Render(const PVG_FT_Raster_Params *params)
+  {
+      char stack[PVG_FT_MINIMUM_POOL_SIZE];
+      size_t length = PVG_FT_MINIMUM_POOL_SIZE;
