+void plutovg_matrix_map(const plutovg_matrix_t* matrix, float x, float y, float* xx, float* yy)
+{
+    *xx = x * matrix->a + y * matrix->c + matrix->e;
+    *yy = x * matrix->b + y * matrix->d + matrix->f;
